Connect-MgGraph -Scopes 'Application.ReadWrite.All'

# Create a multi-tenant app registration
$app = New-MgApplication -BodyParameter @{
    DisplayName    = 'Contoso SaaS App'
    SignInAudience = 'AzureADMultipleOrgs'
    Web = @{
        RedirectUris                  = @('https://app.contoso.com/auth/callback')
        ImplicitGrantSettings = @{
            EnableIdTokenIssuance     = $false
            EnableAccessTokenIssuance = $false
        }
    }
    RequiredResourceAccess = @(
        @{
            ResourceAppId  = '00000003-0000-0000-c000-000000000000'  # MS Graph
            ResourceAccess = @(
                @{ Id = 'e1fe6dd8-ba31-4d61-89e7-88639da4683d'; Type = 'Scope' }  # User.Read
                @{ Id = '37f7f235-527c-4136-accd-4a02d197296e'; Type = 'Scope' }  # openid
            )
        }
    )
}

# Create the home service principal in the publisher tenant
$sp = New-MgServicePrincipal -AppId $app.AppId

Write-Host "App registered: $($app.AppId)"
Write-Host "Home SP objectId: $($sp.Id)"

terraform {
  required_providers {
    azuread = { source = "hashicorp/azuread"; version = "~> 2.50" }
  }
}

resource "azuread_application" "saas_app" {
  display_name    = "Contoso SaaS App"
  sign_in_audience = "AzureADMultipleOrgs"

  web {
    redirect_uris = ["https://app.contoso.com/auth/callback"]
    implicit_grant {
      access_token_issuance_enabled = false
      id_token_issuance_enabled     = false
    }
  }

  required_resource_access {
    resource_app_id = "00000003-0000-0000-c000-000000000000"  # Microsoft Graph
    resource_access {
      id   = "e1fe6dd8-ba31-4d61-89e7-88639da4683d"  # User.Read
      type = "Scope"
    }
  }

  app_role {
    id                   = "00000000-0000-0000-0000-000000000001"
    allowed_member_types = ["User", "Group"]
    description          = "Can read data in the app"
    display_name         = "Reader"
    enabled              = true
    value                = "Reader"
  }

  app_role {
    id                   = "00000000-0000-0000-0000-000000000002"
    allowed_member_types = ["User", "Group"]
    description          = "Full admin access"
    display_name         = "Admin"
    enabled              = true
    value                = "Admin"
  }
}

# Home service principal in publisher tenant
resource "azuread_service_principal" "saas_sp" {
  client_id = azuread_application.saas_app.client_id
}

output "app_client_id" {
  value = azuread_application.saas_app.client_id
}

Connect-MgGraph -Scopes 'Application.ReadWrite.All'

$appId  = '<your-app-client-id>'
$app    = Get-MgApplication -Filter "appId eq '$appId'"

# Export the full manifest to JSON
$manifest = Get-MgApplication -ApplicationId $app.Id
$manifest | ConvertTo-Json -Depth 10 | Out-File './app-manifest.json' -Encoding UTF8
Write-Host 'Manifest exported to app-manifest.json'

# Add an optional claim to include tenant-specific data in the access token
Update-MgApplication -ApplicationId $app.Id -BodyParameter @{
    OptionalClaims = @{
        AccessToken = @(
            @{ Name = 'tenant_ctry'; Essential = $false }
            @{ Name = 'acct';        Essential = $false }
        )
        IdToken = @(
            @{ Name = 'preferred_username'; Essential = $false }
        )
    }
}
Write-Host 'Optional claims updated.'
